.listener-box {
  border: 1px dashed var(--el-border-color);
  border-radius: var(--el-border-radius-base);
  margin-top: 10px;
  padding: 7px;
  position: relative;

  &:hover {
    border-color: var(--el-color-primary);
    .listener-close {
      display: block;
    }
  }

  .listener-close {
    position: absolute;
    top: -7px;
    right: -7px;
    z-index: 1;
    display: none;
  }
}

.listener-btn {
  border: 1px dashed var(--el-border-color);
  height: 30px;
  margin-top: 5px;
  background: #fff;
  display: flex;
  justify-content: center;
  align-items: center;
}

